conversation_type = #{conversationType}, unread_count = #{unreadCount}, last_read_seq = #{lastReadSeq}, is_top = #{isTop}, is_mute = #{isMute}, show_nickname = #{showNickname}, status = #{status}, update_time = #{updateTime}
