UPDATE im_user_conversation
SET unread_count = #{unreadCount},
    update_time = #{updateTime}
WHERE id = #{id}

UPDATE im_user_conversation
SET unread_count = unread_count + #{increment},
    update_time = #{updateTime}
WHERE user_id = #{userId}
  AND conversation_id = #{conversationId}
  AND status = 1

